var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037: <color=#ffd34c>서윤</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037：<color=#ffd34c>アオイ・シズカ</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037: <color=#ffd34c>Seo Yoon</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0037: <color=#ffd34c>徐芸</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"룰루~ 룰루루~","JPN":"ルル～ルルル～～。","ENG":"Lala, lalala!","TWN":"嚕嚕～嚕嚕嚕～"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기분이 좋아 보이는군. 별일인데?","JPN":"珍しくご機嫌だな？","ENG":"You look happy. That's unusual.","TWN":"你心情看起來很好呢。發生什麼事了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"무슨 뜻이죠, 그 말씀은?","JPN":"どういう意味ですか？","ENG":"What do you mean by that?","TWN":"你這話是什麼意思？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"마치 전 행복해하면 안 된다는 것처럼 들립니다만?","JPN":"私の幸せが気に入らないようですね？","ENG":"It sounds as if I'm never supposed to be happy.","TWN":"聽起來好像我不該這麼開心一樣？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아니, 그럴 리가 있겠나?","JPN":"い、いや。そんなわけないだろう？","ENG":"W-what? Of course not.","TWN":"不、不是，我怎麼敢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"난 언제나 자네가 즐겁게 일할 수 있는 환경을 만들어 주려고 노력하고 있다네.","JPN":"私は常に君が楽しく働ける環境を整えるために、最善を尽くしてる。","ENG":"I'm always trying hard to provide the best work environment for you to enjoy.","TWN":"我一直在努力為你創造一個愉快的工作環境。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서 말인데, 얼굴이 밝아 보이는군.","JPN":"それでだな、ずいぶんと表情が明るいが。","ENG":"Speaking of which, you look good.","TWN":"然後，就看到你氣色很好的樣子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭐 좋은 일이라도 있나?","JPN":"何かいい事でもあったのか？","ENG":"Do you have some good news?","TWN":"是有什麼好事嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그야 좋다면 좋은 일이죠.","JPN":"そうとも言えますね。","ENG":"I suppose it can be considered good.","TWN":"說好的話應該可以算好事吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"항상 본사의 들쭉날쭉한 작전수행 능력 때문에 골머리를 앓아 왔었는데......","JPN":"我が社の不安定な作戦遂行能力のせいで、いつも頭を抱えていたのですが……","ENG":"I was having trouble with our company's unreliable mission capability...","TWN":"之前一直在為本公司亂七八糟的作戰達成能力感到頭痛……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"드디어 제 2소대를 편성할 수 있을 것 같습니다.","JPN":"やっと第2小隊を編成できそうです。","ENG":"But I believe we can finally form a 2nd squad.","TWN":"現在終於可以組建第二小隊了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이것도 모두 회사의 재정이 안정된 덕분이죠.","JPN":"これもすべて、会社の財政が安定したおかげです。","ENG":"And this is all thanks to our company's improved financial status.","TWN":"這全多虧公司的財政穩定了下來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제 2소대의 편성이 끝나면 당분간은 스승님의 변덕 때문에 회사가 휘둘리는 일도 없을 겁니다.","JPN":"第2小隊の編成を終えれば、当分の間は師匠の気まぐれに会社が振り回されることもないでしょう。","ENG":"Once the 2nd squad is formed, the company won't have to suffer from Master's unpredictable actions for a while.","TWN":"第二小隊的組建完成後，公司暫時就不用被師父的任性牽著走了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그러니까 쇼핑을 해서 기분이 좋았다는 거였군.","JPN":"……つまり、良い買い物をして機嫌がよかったということだな。","ENG":"So you're saying that you're happy because you went shopping.","TWN":"……所以就是買完東西後，心情變好的意思吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네? 방금 무슨 말씀을 하셨죠?","JPN":"はい？今、何ておっしゃいましたか？","ENG":"Huh? What do you mean by that?","TWN":"咦？您剛才說什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아무것도 아닐세. 그래서 적당한 후보는 찾았나?","JPN":"な、何でもない。それで、適切な候補は見つかったのか？","ENG":"I-it's nothing. So, did you find a reasonable candidate?","TWN":"沒，沒什麼。所以，你找到合適的候補了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"내 기억엔 예전부터 자네 눈이 꽤 높았던 걸로 아는데 말이야.","JPN":"私の記憶では、君の基準はかなり厳しかったはずだが。","ENG":"From what I remember, you've always had high standards.","TWN":"在我的記憶中，你的眼光一直都很高。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 기준을 충족하는 인재라니 나도 기대되는군.","JPN":"それを満たす人材が現れたのなら、私も楽しみだ。","ENG":"I can't wait to meet the person who satisfied your standards.","TWN":"竟然能滿足你的標準，我也跟著期待了起來呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"뭐, 그 정도는 아닙니다만...... 장래가 기대되는 주니어라고 해 두죠.","JPN":"まあ、それほどでもないですが……将来有望とでも言いましょうか。","ENG":"Well, don't get too excited. Let's just say she's a promising talent.","TWN":"這個嘛，雖然不到那個程度……但是個未來值得期待的年輕人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이름은 서윤, 연령 19세. 신장 168.5cm, 체중 50.7kg.","JPN":"名前はアオイ・シズカ、年齢は19。身長168.5cm、体重50.7kg。","ENG":"Name's Seo Yoon. Age 19. Height 168.5cm. Weight 50.7kg.","TWN":"名字叫徐芸，年齡19歲。身高168.5cm，體重50.7kg。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"단독 카운터 소대인 알트 소대의 리더입니다.","JPN":"単独カウンター小隊である、アルト小隊のリーダーです。","ENG":"She's the leader of an independent Counter squad, the ALT Squad.","TWN":"單獨制裁者小隊，阿爾特小隊的隊長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"단독 카운터 소대?","JPN":"単独カウンター小隊？","ENG":"Independent Counter squad?","TWN":"單獨制裁者小隊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아, 이쪽에서는 보통 언더그라운드라고 하죠. 들어보셨을 텐데요?","JPN":"あ、こっちでは通常アンダーグラウンドと呼ばれます。聞いたことはありますよね？","ENG":"Oh, we usually call it the Underground. You probably heard of it before.","TWN":"是啊，這邊一般都叫地下世界，我想您應該聽過吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"태스크포스에 소속되지 않고 활동하는 미인증 카운터들 말하는 거 아닌가?","JPN":"タスクフォースカンパニーに所属せずに活動する、未認証カウンターのことか？","ENG":"You mean the unauthorized Counters without an affiliation with a TASKFORCE?","TWN":"你是不是在說不屬於特遣勢力，活動未受認證的制裁者？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"설마 자네가 그쪽 인력을 스카우트 해 올 줄은 몰랐는걸?","JPN":"まさか君が、そっちの人材をスカウトするとは。","ENG":"I didn't expect you of all people to scout someone from there.","TWN":"沒想到你竟然會從那裡挖掘人才。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"평소에 언더그라운드 따위는 업계의 생태계를 파괴하는 암적인 존재라고 불 같은 열변을 토했던 것 같은데......","JPN":"普段はアンダーグラウンドなど、業界の生態系を破壊するガンのような存在だと、熱弁していたのに……","ENG":"I recall you ranting about the Underground being a cancerous entity that is destroying our industry...","TWN":"我記得妳以前大剌剌地說過，地下世界是個破壞業界生態，有如癌症一般的存在……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 의견에는 전혀 변함이 없습니다.","JPN":"その考えに変わりはありません。","ENG":"And I stand by that opinion.","TWN":"我對這個觀點完全沒有異議。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"다만 그 암덩이는 이제 우리 암덩이라서 말이죠.","JPN":"ただそのガンは、これから我々のものになります。","ENG":"But that cancer is now our cancer.","TWN":"只是那個癌症，現在已經變成我們的腫瘤了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그 관용구는 그런 식으로 쓰는 게 아닌 것 같지만, 뭐 넘어가도록 하지.","JPN":"……なるほど。まあ、わかった。","ENG":"You don't usually use that idiom like that, but I'll let it pass.","TWN":"……話不是這樣說的。算了，繼續吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서 실력은 어떻지?","JPN":"それで、実力の方はどうだ？","ENG":"So, how good is she?","TWN":"所以她實力如何？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"CRF 출력은 관리국 기준으로 따지자면 B급 정도 됩니다.","JPN":"CRF出力は、管理局の基準によるとB級程度です。","ENG":"Her CRF is about Grade B according to the Administration's standards.","TWN":"CRF輸出按照管理局標準計算的話，大約在B級左右。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론 비공식이지만요.","JPN":"もちろん非公式ですが。","ENG":"Unofficial, of course.","TWN":"當然，是非正式的就是了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 등급과는 별개로 전적이 꽤 좋습니다.","JPN":"しかし、ランクとは別に戦績がかなり優秀です。","ENG":"But regardless of her grade, her squad has shown great success.","TWN":"但是和評價不同，她的戰績非常好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근 1년 사이에만도 서른 개가 넘는 작전을 완수했더군요.","JPN":"ここ1年だけでも、30以上の作戦を遂行しました。","ENG":"In just the past year, they already completed over 30 missions.","TWN":"在最近短短一年內，完成了三十場以上的作戰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"호오?","JPN":"ほお？","ENG":"Oh?","TWN":"哦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"레퍼런스 체크 상으로는 계약시에 조금 까다롭기는 하지만......","JPN":"レファレンスをチェックしたところ、契約は少々煩わしいようですが……","ENG":"It's a bit difficult to sign a contract with them due to the lack of references, but...","TWN":"雖然在資歷審核時，簽約上碰到了一點麻煩……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"일처리 하나는 깔끔하기로 정평이 났더군요.","JPN":"任務はきっちりこなすことで、評判になってました。","ENG":"They are well-known for their professionalism.","TWN":"但他們做事向來乾淨俐落。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"가장 마음에 드는 건 알트 소대 전체가 리더인 그녀의 결정에 따라 움직인다는 점입니다.","JPN":"一番気に入ったのは、全アルト小隊員がリーダーである彼女の決定に従うという点です。","ENG":"What I liked the most about them is that the entire ALT Squad follows their leader's decision unanimously.","TWN":"最令人中意的是，阿爾特小隊全體會把她當成領袖，根據她的決定來行動。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"손발도 안 맞는 인원들을 신규 소대로 편성하거나,","JPN":"息の合わないメンバーを新規小隊として編成したり、","ENG":"Which means, we don't have to create a new squad that can't work together.","TWN":"這就代表，把沒默契的成員編成新小隊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"자기가 무슨 고독한 늑대라도 되는 줄 아는 얼간이들을 펜릴 소대에 집어넣는 끔찍한 일을 하지 않아도 된다는 뜻이죠.","JPN":"一匹狼だと思い込んでる愚か者どもをフェンリル小隊に編入したりするような、おぞましい決断をする必要がないという意味です。","ENG":"Nor do we have to reinforce Fenrir Squad with idiots who think they're some sort of lone wolves.","TWN":"或是把自以為是一匹孤狼的笨蛋編進芬里爾小隊，我們就算不用做這些可怕的事情也沒關係了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......충분히 이해했네.","JPN":"……君の言いたいことは十分理解した。","ENG":"Understood.","TWN":"……我完全明白了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 계약 조건이 까다롭다면서? 벌써 협의가 끝난 건가?","JPN":"しかし、契約条件がややこしいんだろう？すでに協議したのか？","ENG":"But you mentioned the difficulty of signing their contracts. Have you already reached an agreement?","TWN":"話說，契約條件不是很苛刻嗎？你們協商已經結束了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아니요. 구두 합의 정도만 해둔 상황입니다.","JPN":"いいえ、まだ口頭での合意だけです。","ENG":"No. We just have an oral agreement for now.","TWN":"沒有，只有口頭同意的程度而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최종 계약서는 조금 있다가 만나서 작성하기로 했죠.","JPN":"最終契約書は、後ほど会って作成することにしました。","ENG":"Everyone will be here to sign the final contract later today.","TWN":"最終契約要在待會見面後再簽。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 까다롭다고 해 봐야, 어차피 언더그라운드에서나 날뛰던 애송이 아가씨입니다.","JPN":"それにややこしいと言っても、どうせアンダーグラウンドで暴れてたじゃじゃ馬娘です。","ENG":"And how hard could it be to sign a contract with some rookies that worked in the Underground?","TWN":"而且，就算有點難搞，終究也只是在地下世界囂張的小丫頭而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런 파릇파릇한 애송이를 요리하는 것도 경영의 묘미라고 할 수 있죠.","JPN":"そういう青臭い若者を言いくるめるのも、経営の醍醐味ですから。","ENG":"Serving up those kind of rookies is part of the charm we have in managing a company.","TWN":"調教這些初出茅廬的小鬼也能說是經營的樂趣呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이제 겨우 메이저 스테이지로 올라오려는 신인들에게 진정한 공인 태스크포스의 혹독한 세계를 제대로 가르쳐 줄 생각입니다.","JPN":"やっとメインステージへ上がる新人に、本物の公認タスクフォースカンパニーの世界を、みっちり教え込んでやるつもりです。","ENG":"I am going to teach them a harsh lesson on what it really takes to become a fully authorized official TASKFORCE.","TWN":"就讓我來告訴這些好不容易登上主舞台的新人，真正的公認特遣勢力，這個殘酷世界是怎麼一回事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"어, 음...... 그래......","JPN":"あ、うん……そうか……","ENG":"Oh, um... Okay...","TWN":"呃，嗯……好喔……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"잘 됐으면 좋겠군......","JPN":"うまくいくといいな……","ENG":"I hope everything goes well...","TWN":"希望你一切順利……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아, 벌써 시간이 이렇게 됐군요.","JPN":"あ、もうこんな時間ですか。","ENG":"Oh, look at the time.","TWN":"啊，都已經這麼晚了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그럼 전 이만 서윤 양과 계약서를 작성하러 가 보겠습니다.","JPN":"では、アオイ・シズカとの契約書を作成して来ます。","ENG":"I'm off to sign the contract with Seo Yoon and her squad.","TWN":"那我現在去跟徐芸小姐簽約了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그, 그래. 행운을 비네......","JPN":"あ、ああ。幸運を祈る……","ENG":"Y-yes... Best of luck to you...","TWN":"喔，好，祝你好運……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};